        <!-- Black -->
        <div class="edition" data-edition="black" data-state="coming-soon">
            <canvas class="edition-canvas"></canvas>
            <div class="edition-info">
                <div class="edition-name">Obsidian</div>
                <div class="edition-status">MINTING NEXT SEASON: AUTUMN</div>
                <!-- No button for coming soon -->
            </div>
        </div>

    </section>

    <script>
        /**
         * WastedToken Mint - Procedural Coin Engine
         * 
         * Core Logic:
         * 1. We use HTML5 Canvas API to draw the coin faces procedurally.
         * 2. We simulate 3D rotation using CSS transforms on the container, but we redraw
         *    the canvas content based on the current rotation angle to create the "rake" effect.
         * 3. The `setTime(t)` function is deterministic: it calculates angles from t and redraws.
         */

        const heroCanvas = document.getElementById('coin-hero');
        const ctx = heroCanvas.getContext('2d');

        // Configuration
        const CONFIG = {
            radius: 140,
            reedCount: 16,
            rotationSpeed: 0.005, // Base speed for animation loop
            t: 0 // Current time in [0, 1]
        };

        // Resize canvas to fit container
        function resizeHero() {
            const wrapper = document.getElementById('coin-wrapper');
            const rect = wrapper.getBoundingClientRect();
            heroCanvas.width = rect.width;
            heroCanvas.height = rect.height;
            CONFIG.radius = Math.min(rect.width, rect.height) / 2 - 10; // Padding
        }

        window.addEventListener('resize', resizeHero);
        resizeHero();

        /**
         * Draws the coin face.
         * @param {CanvasRenderingContext2D} ctx 
         * @param {number} rotationY (radians) - Rotation around vertical axis
         * @param {number} rotationX (radians) - Rotation around horizontal axis (flip)
         */
        function drawCoinFace(ctx, rotationY, rotationX, type) {
            const r = CONFIG.radius;
            const centerX = heroCanvas.width / 2;
            const centerY = heroCanvas.height / 2;

            // Clear
            ctx.clearRect(0, 0, heroCanvas.width, heroCanvas.height);

            // --- 1. The Base Metal (Simulated via Gradients) ---

            // We simulate the metallic surface by drawing a gradient that shifts 
            // based on rotation to create the "rake" effect.

            // Determine highlight position based on rotation
            // As coin rotates Y, light moves X. As coin flips X, light moves Y.
            const shineX = Math.cos(rotationY) * (r * 0.6); 
            const shineY = Math.sin(rotationY) * (r * 0.6);

            // Create a complex gradient for the metal body
            // We use a mix of radial and linear gradients to simulate curvature
            const grad = ctx.createRadialGradient(
                centerX + shineX, centerY + shineY, r * 0.1, 
                centerX, centerY, r
            );

            // Base colors based on type
            let baseColor = '#CD7F32'; // Bronze default
            if (type === 'silver') baseColor = '#C0C0C0';
            if (type === 'gold') baseColor = '#FFD700';
            if (type === 'black') baseColor = '#1a1a1a';

            grad.addColorStop(0, lighten(baseColor, 40)); // Highlight
            grad.addColorStop(0.3, baseColor);           // Mid-tone
            grad.addColorStop(1, darken(baseColor, 20));  // Shadow

            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(centerX, centerY, r, 0, Math.PI * 2);
            ctx.fill();

            // --- 2. The Embossed Emblem (Front Face) ---
            // Only visible when rotationX is near 0 (flat). 
            // We use shadowBlur to create the "raised" look.

            const isFrontVisible = Math.abs(rotationX) < 0.5; // Threshold for visibility

            if (isFrontVisible) {
                ctx.save();

                // Calculate emboss offset based on rotation X
                // When flipped, we want to see the back face, so we hide front or invert logic
                // For simplicity in this demo: 
                // 0.0 -> Front Face
                // PI -> Back Face

                if (rotationX < Math.PI / 2) {
                    // Draw Front Face
                    ctx.shadowColor = 'rgba(0,0,0,0.5)';
                    ctx.shadowBlur = 15;
                    ctx.shadowOffsetY = 5;

                    // Emblem: A stylized "W" inside a gear/circle
                    ctx.translate(centerX, centerY);

                    // Outer Ring (Embossed border)
                    ctx.beginPath();
                    ctx.arc(0, 0, r * 0.85, 0, Math.PI * 2);
                    ctx.lineWidth = 10;
                    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
                    ctx.stroke();

                    // Inner Emblem Path
                    ctx.beginPath();
                    ctx.arc(0, 0, r * 0.6, 0, Math.PI * 2);
                    ctx.lineWidth = 4;
                    ctx.strokeStyle = 'rgba(255,255,255,0.8)';
                    ctx.stroke();

                    // Text "WASTED"
                    ctx.fillStyle = '#fff';
                    ctx.font = `bold ${r * 0.15}px sans-serif`;
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';

                    // Simple procedural text drawing
                    ctx.save();
                    ctx.rotate(Math.PI / 4); // Tilt text for style
                    ctx.fillText("WASTED", 0, -r * 0.15);
                    ctx.restore();

                    ctx.restore();
                } else {
                    // Draw Back Face (Denomination)
                    ctx.shadowColor = 'rgba(0,0,0,0.8)';
                    ctx.shadowBlur = 20;
                    ctx.shadowOffsetY = 10;

                    ctx.save();
                    ctx.translate(centerX, centerY);

                    // Back Ring
                    ctx.beginPath();
                    ctx.arc(0, 0, r * 0.9, 0, Math.PI * 2);
                    ctx.lineWidth = 8;
                    ctx.strokeStyle = 'rgba(255,255,255,0.4)';
                    ctx.stroke();

                    // Text "10,000 TOKENS"
                    ctx.fillStyle = '#fff';
                    ctx.font = `bold ${r * 0.12}px sans-serif`;
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';

                    ctx.fillText("10,000", 0, -r * 0.15);
                    ctx.font = `${r * 0.08}px sans-serif`;
                    ctx.fillText("TOKENS", 0, r * 0.15);

                    // Small decorative element (Star)
                    ctx.beginPath();
                    ctx.arc(0, 0, r * 0.3, 0, Math.PI * 2);
                    ctx.fillStyle = 'rgba(255,255,255,0.1)';
                    ctx.fill();

                    ctx.restore();
                }
            }

            // --- 3. The Reeded Edge ---
            // Drawn as a border that looks like ridges catching light

            ctx.save();
            ctx.beginPath();
            ctx.arc(centerX, centerY, r + 4, 0, Math.PI * 2); // Slightly larger to encompass face
            ctx.clip();

            // Create the reeded texture
            const edgeWidth = 12;
            const numReeds = CONFIG.reedCount;
            const angleStep = (Math.PI * 2) / numReeds;

            for (let i = 0; i < numReeds; i++) {
                ctx.save();
                ctx.translate(centerX, centerY);
                ctx.rotate(i * angleStep);

                // Draw a slice of the edge
                ctx.beginPath();
                ctx.rect(-edgeWidth/2, -r, edgeWidth, r*2);
                ctx.clip();

                // Gradient for the reed (Light/Dark)
                const reedGrad = ctx.createLinearGradient(0, 0, 0, r * 2);
                // The highlight on the reed moves as we rotate Y
                const lightPos = Math.sin(rotationY + i * angleStep) * 10; 

                reedGrad.addColorStop(0, '#000');
                reedGrad.addColorStop(0.3, lighten(baseColor, 20)); // Highlight
                reedGrad.addColorStop(0.5, baseColor);
                reedGrad.addColorStop(1, '#000');

                ctx.fillStyle = reedGrad;
                ctx.fillRect(-edgeWidth/2, -r, edgeWidth, r*2);

                ctx.restore();
            }
            ctx.restore();
        }

        // Helper to lighten/darken hex colors
        function lighten(color, percent) {
            const num = parseInt(color.replace("#",""),16),
            R=num>>16,G=(num>>8)&0x0FF,B=num&0x0FF;
            return "#"+(0x100000+(Math.round((R*(100+percent))/100)<<16)+
            (Math.round((G*(100+percent))/100)<<8)+(Math.round((B*(100+percent))/100))).toString(16);
        }

        function darken(color, percent) {
             const num = parseInt(color.replace("#",""),16),
            R=num>>16,G=(num>>8)&0x0FF,B=num&0x0FF;
            return "#"+(0x100000+(Math.round((R*(100-percent))/100)<<16)+
            (Math.round((G*(100-percent))/100)<<8)+(Math.round((B*(100-percent))/100))).toString(16);
        }

        /**
         * Main Render Function called by setTime(t) and Animation Loop
         */
        function render(timeVal) {
            CONFIG.t = timeVal;

            // Calculate Rotation Angles
            // Vertical Spin: 2 full rotations (4PI) over the loop
            const rotY = timeVal * 4 * Math.PI; 

            // Horizontal Flip: 1 full rotation (2PI) over the loop
            const rotX = timeVal * 2 * Math.PI;

            // Apply CSS Transform for 3D perspective
            const wrapper = document.getElementById('coin-wrapper');
            wrapper.style.transform = `rotateY(${rotY}rad) rotateX(${rotX}rad)`;

            // Draw the coin content (Procedural Redraw)
            drawCoinFace(ctx, rotY, rotX, 'bronze');
        }

        /**
         * Programmatic API Implementation
         */

        // 1. Animation Loop
        let animationId = null;
        let lastTime = 0;

        function loop(timestamp) {
            if (!lastTime) lastTime = timestamp;

            // Calculate delta time to drive the 't' variable smoothly
            // We want t to go from 0 to 1 over roughly 5 seconds (adjustable)
            const now = timestamp / 1000; 
            // Simple linear interpolation for demo purposes, or just incrementing
            // To make it deterministic based on timeVal passed to setTime, we usually use a clock.
            // But the prompt implies `setTime` controls the state.

            // Let's drive 't' based on elapsed time since start
            const duration = 5; // seconds for full loop
            const currentT = (now % duration) / duration;

            render(currentT);
            animationId = requestAnimationFrame(loop);
        }

        function pause() {
            if (animationId) {
                cancelAnimationFrame(animationId);
                animationId = null;
            }
        }

        // 2. The API Object
        window.demo = {
            canvas: heroCanvas,

            setTime: function(t) {
                // Clamp t to [0, 1]
                const safeT = Math.max(0, Math.min(1, t));
                render(safeT);
            },

            pause: function() {
                pause();
            }
        };

        // Start the loop
        animationId = requestAnimationFrame(loop);

    </script>
</body>
</html>
